"use client"

import Link from "next/link"
import { useMemo, useState } from "react"

type CoachSuggestion = {
  label: string
  prompt: string
}

type CoachRecommendation = {
  href: string
  title: string
  description: string
  badge: string
}

type CoachResponse = {
  answer?: string
  message?: string
  recommendations?: CoachRecommendation[]
  fallback?: boolean
}

type AICoachPanelProps = {
  eyebrow?: string
  title?: string
  description?: string
  courseSlug?: string
  contentSlug?: string
  suggestions?: CoachSuggestion[]
}

export default function AICoachPanel({
  eyebrow = "Coach IA",
  title = "Pergunte para a K9 IA",
  description = "Receba uma resposta objetiva, com passos praticos e sugestoes de conteudos da propria plataforma.",
  courseSlug,
  contentSlug,
  suggestions = defaultSuggestions,
}: AICoachPanelProps) {
  const [question, setQuestion] = useState("")
  const [lastQuestion, setLastQuestion] = useState("")
  const [result, setResult] = useState<CoachResponse | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [isLoading, setIsLoading] = useState(false)

  const canAsk = question.trim().length >= 8
  const activeSuggestions = useMemo(() => suggestions.slice(0, 4), [suggestions])

  async function ask(prompt: string) {
    const trimmed = prompt.trim()
    if (trimmed.length < 8) {
      setError("Escreva pelo menos 8 caracteres para eu conseguir ajudar melhor.")
      return
    }

    setError(null)
    setLastQuestion(trimmed)
    setIsLoading(true)

    try {
      const response = await fetch("/api/ai/coach", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          question: trimmed,
          courseSlug,
          contentSlug,
        }),
      })

      const payload = (await response.json().catch(() => null)) as CoachResponse | null

      if (!response.ok) {
        setResult(null)
        setError(payload?.message || "Nao foi possivel responder agora. Tente novamente em instantes.")
        return
      }

      setResult(payload)
    } catch {
      setResult(null)
      setError("A conexao com o assistente falhou. Tente novamente em alguns segundos.")
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <section
      id="coach-k9"
      className="rounded-[32px] border border-white/10 bg-[linear-gradient(150deg,rgba(14,116,144,0.2),rgba(15,23,42,0.94)_42%,rgba(12,74,110,0.85)),radial-gradient(circle_at_top_right,rgba(245,158,11,0.18),transparent_32%)] p-6 shadow-2xl shadow-black/25 md:p-8"
    >
      <div className="grid gap-6 xl:grid-cols-[0.9fr_1.1fr]">
        <div className="space-y-4">
          <div>
            <p className="text-sm uppercase tracking-[0.22em] text-amber-200/85">{eyebrow}</p>
            <h2 className="mt-3 text-3xl font-semibold text-white">{title}</h2>
            <p className="mt-3 max-w-xl text-sm leading-7 text-slate-200">{description}</p>
          </div>

          <div className="rounded-[24px] border border-white/10 bg-black/20 p-4">
            <p className="text-xs uppercase tracking-[0.18em] text-slate-400">Perguntas que funcionam bem</p>
            <div className="mt-3 flex flex-wrap gap-2">
              {activeSuggestions.map((suggestion) => (
                <button
                  key={suggestion.label}
                  type="button"
                  onClick={() => {
                    setQuestion(suggestion.prompt)
                    void ask(suggestion.prompt)
                  }}
                  className="rounded-full border border-white/10 bg-white/10 px-3 py-2 text-left text-sm text-slate-100 transition hover:border-amber-300/30 hover:bg-white/15"
                >
                  {suggestion.label}
                </button>
              ))}
            </div>
          </div>

          <div className="rounded-[24px] border border-dashed border-white/10 bg-white/5 p-4 text-sm text-slate-300">
            A resposta prioriza educacao, rotina e seguranca. Em caso de dor, lesao, reatividade grave ou suspeita
            clinica, a IA orienta procurar veterinario ou adestrador presencial.
          </div>
        </div>

        <div className="space-y-4">
          <div className="rounded-[28px] border border-white/10 bg-slate-950/50 p-4 backdrop-blur sm:p-5">
            <label htmlFor="coach-question" className="text-sm font-medium text-slate-200">
              O que voce quer destravar agora?
            </label>
            <textarea
              id="coach-question"
              value={question}
              onChange={(event) => setQuestion(event.target.value)}
              rows={5}
              placeholder="Ex.: meu cao fica agitado quando chegam visitas e eu quero uma rotina de treino para as proximas duas semanas."
              className="mt-3 w-full rounded-[24px] border border-white/10 bg-white/10 px-4 py-4 text-sm text-white placeholder:text-slate-400 focus:border-amber-300/60 focus:outline-none focus:ring-2 focus:ring-amber-500/20"
            />

            <div className="mt-4 flex flex-wrap items-center justify-between gap-3">
              <p className="text-xs uppercase tracking-[0.18em] text-slate-500">
                Contexto: {courseSlug ? "curso atual" : contentSlug ? "aula atual" : "catalogo e conteudos"}
              </p>
              <button
                type="button"
                onClick={() => void ask(question)}
                disabled={!canAsk || isLoading}
                className="rounded-2xl bg-[linear-gradient(135deg,#f59e0b,#fb7185)] px-5 py-3 text-sm font-semibold text-slate-950 shadow-lg shadow-amber-500/25 transition hover:-translate-y-0.5 disabled:cursor-not-allowed disabled:opacity-50"
              >
                {isLoading ? "Analisando..." : "Perguntar para a IA"}
              </button>
            </div>
          </div>

          {error && (
            <div className="rounded-[24px] border border-rose-300/20 bg-rose-500/10 p-4 text-sm text-rose-100">
              {error}
            </div>
          )}

          {result && (
            <div className="space-y-4">
              <div className="rounded-[28px] border border-white/10 bg-white/10 p-5">
                <div className="flex flex-wrap items-center gap-2">
                  <span className="rounded-full bg-amber-500/15 px-3 py-1 text-xs uppercase tracking-[0.18em] text-amber-100">
                    Resposta
                  </span>
                  {result.fallback && (
                    <span className="rounded-full bg-white/10 px-3 py-1 text-xs uppercase tracking-[0.18em] text-slate-200">
                      Modo orientado
                    </span>
                  )}
                </div>

                {lastQuestion && (
                  <p className="mt-3 text-sm text-slate-400">
                    Pergunta: <span className="text-slate-200">{lastQuestion}</span>
                  </p>
                )}

                <div className="mt-4 whitespace-pre-wrap text-sm leading-7 text-slate-100">
                  {result.answer || result.message}
                </div>
              </div>

              {result.recommendations && result.recommendations.length > 0 && (
                <div className="rounded-[28px] border border-white/10 bg-black/20 p-5">
                  <div className="flex items-center justify-between gap-3">
                    <div>
                      <p className="text-xs uppercase tracking-[0.18em] text-slate-400">Proximo passo</p>
                      <h3 className="mt-2 text-xl font-semibold text-white">Conteudos que combinam com a sua pergunta</h3>
                    </div>
                  </div>

                  <div className="mt-4 grid gap-3 md:grid-cols-2">
                    {result.recommendations.map((recommendation) => (
                      <Link
                        key={`${recommendation.href}-${recommendation.title}`}
                        href={recommendation.href}
                        className="rounded-[22px] border border-white/10 bg-white/10 p-4 transition hover:bg-white/15"
                      >
                        <span className="rounded-full bg-cyan-500/15 px-3 py-1 text-xs uppercase tracking-[0.16em] text-cyan-100">
                          {recommendation.badge}
                        </span>
                        <h4 className="mt-3 text-base font-semibold text-white">{recommendation.title}</h4>
                        <p className="mt-2 text-sm leading-6 text-slate-300">{recommendation.description}</p>
                      </Link>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </section>
  )
}

const defaultSuggestions: CoachSuggestion[] = [
  {
    label: "Rotina para filhote",
    prompt: "Monte uma rotina simples de cursos, dicas e pratica para um filhote com muita energia.",
  },
  {
    label: "Passeio sem puxar",
    prompt: "Quais os primeiros passos para reduzir puxoes no passeio e que tipo de aula devo estudar primeiro?",
  },
  {
    label: "Socializacao",
    prompt: "Quero melhorar a socializacao do meu cao sem exagerar nos estimulos. Como organizar isso?",
  },
  {
    label: "Plano de 7 dias",
    prompt: "Crie um plano de estudo de 7 dias com dicas e pratica para obediencia basica.",
  },
]
